from dataclasses import dataclass
from typing import Optional


@dataclass
class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional["ASTNode"] = None
    right: Optional["ASTNode"] = None
    operand: Optional["ASTNode"] = None


class _Tokenizer:
    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0

    def peek(self) -> Optional[str]:
        self._skip_whitespace()
        if self.pos >= len(self.expression):
            return None
        return self.expression[self.pos]

    def consume(self) -> str:
        self._skip_whitespace()
        if self.pos >= len(self.expression):
            raise ValueError("Unexpected end of expression")
        char = self.expression[self.pos]
        self.pos += 1
        return char

    def _skip_whitespace(self):
        while self.pos < len(self.expression) and self.expression[self.pos].isspace():
            self.pos += 1

    def parse_number(self) -> float:
        self._skip_whitespace()
        start = self.pos
        has_decimal = False

        while self.pos < len(self.expression):
            char = self.expression[self.pos]
            if char.isdigit():
                self.pos += 1
            elif char == "." and not has_decimal:
                has_decimal = True
                self.pos += 1
            else:
                break

        if start == self.pos:
            raise ValueError("Expected number")

        try:
            return float(self.expression[start : self.pos])
        except ValueError:
            raise ValueError(f"Invalid number: {self.expression[start : self.pos]}")

    def has_more(self) -> bool:
        self._skip_whitespace()
        return self.pos < len(self.expression)


def parse(expression: str) -> ASTNode:
    if not expression or expression.strip() == "":
        raise ValueError("Empty expression")

    tokenizer = _Tokenizer(expression)
    result = _parse_expression(tokenizer)

    if tokenizer.has_more():
        raise ValueError(f"Unexpected character: {tokenizer.peek()}")

    return result


def _parse_expression(tokenizer: _Tokenizer) -> ASTNode:
    left = _parse_term(tokenizer)

    while tokenizer.has_more():
        op = tokenizer.peek()
        if op in ("+", "-"):
            tokenizer.consume()
            right = _parse_term(tokenizer)
            left = ASTNode(type="binop", op=op, left=left, right=right)
        else:
            break

    return left


def _parse_term(tokenizer: _Tokenizer) -> ASTNode:
    left = _parse_factor(tokenizer)

    while tokenizer.has_more():
        op = tokenizer.peek()
        if op in ("*", "/"):
            tokenizer.consume()
            right = _parse_factor(tokenizer)
            left = ASTNode(type="binop", op=op, left=left, right=right)
        else:
            break

    return left


def _parse_factor(tokenizer: _Tokenizer) -> ASTNode:
    if tokenizer.peek() == "-":
        tokenizer.consume()
        operand = _parse_primary(tokenizer)
        return ASTNode(type="unary", op="-", operand=operand)

    return _parse_primary(tokenizer)


def _parse_primary(tokenizer: _Tokenizer) -> ASTNode:
    char = tokenizer.peek()

    if char == "(":
        tokenizer.consume()
        node = _parse_expression(tokenizer)
        if tokenizer.peek() != ")":
            raise ValueError("Unmatched parenthesis")
        tokenizer.consume()
        return node

    if char and (char.isdigit() or char == "."):
        value = tokenizer.parse_number()
        return ASTNode(type="number", value=value)

    if char is None:
        raise ValueError("Unexpected end of expression")

    raise ValueError(f"Unexpected character: {char}")


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        assert node.value is not None
        return node.value

    if node.type == "unary":
        assert node.operand is not None
        if node.op == "-":
            return -evaluate(node.operand)
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == "binop":
        assert node.left is not None
        assert node.right is not None
        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")
